17	// RBTDRI — tabtarget invocation layer for theurge
18	//
19	// Theurge invokes bottle operations exclusively through tabtargets, never
20	// reimplementing bash command logic. This module provides:
21	//
22	//   1. Tabtarget discovery — imprint-scoped, global, or nameplate-scoped
23	//   2. Tabtarget execution with BURV isolation — per-invocation output/temp dirs
24	//   3. Ifrit verdict parsing — extract verdict from ifrit stdout + exit code
25	//   4. BURV fact file reading — extract structured output from tabtarget results
26	
27	use std::path::{Path, PathBuf};
28	use std::process::Command;
29	
30	use crate::rbtdre_engine::rbtdre_Verdict;
31	use crate::rbtdrm_manifest::RBTDRM_COLOPHON_BARK;
32	
33	/// Ifrit binary name inside the bottle container.
34	const RBTDRI_IFRIT_BINARY: &str = "rbid";
35	
36	/// BUK dispatch output subdirectory — tabtargets write facts to BURV_OUTPUT_ROOT_DIR/current.
37	/// Matches BURD_OUTPUT_DIR = "${BURC_OUTPUT_ROOT_DIR}/current" from bud_dispatch.sh.
38	pub const RBTDRI_BURV_OUTPUT_SUBDIR: &str = "current";
39	
40	// ── Invocation result ────────────────────────────────────────
41	
42	/// Captured output from a tabtarget invocation.
43	#[derive(Debug)]
44	pub struct rbtdri_InvokeResult {
45	    pub stdout: String,
46	    pub stderr: String,
47	    pub exit_code: i32,
48	    pub burv_output: PathBuf,
49	}
50	
51	// ── Invocation context ───────────────────────────────────────
52	
53	/// Per-case invocation context. Tracks BURV isolation state so each tabtarget
54	/// invocation within a case gets its own output and temp directories, matching
55	/// the zbuto_invoke() pattern from buto_operations.sh.
56	pub struct rbtdri_Context {
57	    pub(crate) project_root: PathBuf,
58	    pub(crate) nameplate: String,
59	    pub(crate) burv_root: PathBuf,
60	    pub(crate) invoke_count: u32,
61	}
62	
63	impl rbtdri_Context {
64	    pub fn new(project_root: &Path, nameplate: &str, burv_root: &Path) -> Self {
65	        Self {
66	            project_root: project_root.to_path_buf(),
67	            nameplate: nameplate.to_string(),
68	            burv_root: burv_root.to_path_buf(),
69	            invoke_count: 0,
70	        }
71	    }
72	
73	    pub fn nameplate(&self) -> &str {
74	        &self.nameplate
75	    }
76	
77	    pub fn project_root(&self) -> &Path {
78	        &self.project_root
79	    }
80	}
81	
82	// ── Tabtarget discovery ──────────────────────────────────────
83	
84	/// Find the tabtarget script for a colophon + imprint (nameplate or role).
85	///
86	/// Scans tt/ for files matching `{colophon}.*.{imprint}.sh`.
87	/// Returns error if zero or multiple matches — exactly one must exist.
88	pub fn rbtdri_find_tabtarget(
89	    project_root: &Path,
90	    colophon: &str,
91	    nameplate: &str,
92	) -> Result<PathBuf, String> {
93	    let tt_dir = project_root.join("tt");
94	    let prefix = format!("{}.", colophon);
95	    let suffix = format!(".{}.sh", nameplate);
96	
97	    let entries = std::fs::read_dir(&tt_dir)
98	        .map_err(|e| format!("rbtdri: cannot read tt/ directory: {}", e))?;
99	
100	    let matches: Vec<PathBuf> = entries
101	        .filter_map(|entry| entry.ok())
102	        .map(|entry| entry.path())
103	        .filter(|path| {
104	            if let Some(name) = path.file_name().and_then(|n| n.to_str()) {
105	                name.starts_with(&prefix) && name.ends_with(&suffix)
106	            } else {
107	                false
108	            }
109	        })
110	        .collect();
111	
112	    match matches.len() {
113	        0 => Err(format!(
114	            "rbtdri: no tabtarget for colophon '{}' nameplate '{}'",
115	            colophon, nameplate
116	        )),
117	        1 => Ok(matches.into_iter().next().unwrap()),
118	        n => Err(format!(
119	            "rbtdri: {} tabtargets match colophon '{}' nameplate '{}' — expected exactly one",
120	            n, colophon, nameplate
121	        )),
122	    }
123	}
124	
125	/// Find a global tabtarget (no imprint suffix).
126	///
127	/// Scans tt/ for files matching `{colophon}.{frontispiece}.sh` (exactly two dots).
128	/// Rejects files with imprint suffixes (three+ dots).
129	pub fn rbtdri_find_tabtarget_global(
130	    project_root: &Path,
131	    colophon: &str,
132	) -> Result<PathBuf, String> {
133	    let tt_dir = project_root.join("tt");
134	    let prefix = format!("{}.", colophon);
135	
136	    let entries = std::fs::read_dir(&tt_dir)
137	        .map_err(|e| format!("rbtdri: cannot read tt/ directory: {}", e))?;
138	
139	    let matches: Vec<PathBuf> = entries
140	        .filter_map(|entry| entry.ok())
141	        .map(|entry| entry.path())
142	        .filter(|path| {
143	            if let Some(name) = path.file_name().and_then(|n| n.to_str()) {
144	                if name.starts_with(&prefix) && name.ends_with(".sh") {
145	                    // Global: no imprint — exactly one part between colophon and .sh
146	                    let middle = &name[prefix.len()..name.len() - 3]; // strip ".sh"
147	                    !middle.contains('.')
148	                } else {
149	                    false
150	                }
151	            } else {
152	                false
153	            }
154	        })
155	        .collect();
156	
157	    match matches.len() {
158	        0 => Err(format!(
159	            "rbtdri: no global tabtarget for colophon '{}'",
160	            colophon
161	        )),
162	        1 => Ok(matches.into_iter().next().unwrap()),
163	        n => Err(format!(
164	            "rbtdri: {} global tabtargets match colophon '{}' — expected exactly one",
165	            n, colophon
166	        )),
167	    }
168	}
169	
170	// ── Tabtarget invocation with BURV isolation ─────────────────
171	
172	/// Internal: execute a resolved tabtarget with BURV isolation and optional extra env vars.
173	fn rbtdri_invoke_impl(
174	    ctx: &mut rbtdri_Context,
175	    tabtarget: &Path,
176	    args: &[&str],
177	    extra_env: &[(&str, &str)],
178	) -> Result<rbtdri_InvokeResult, String> {
179	    let invoke_num = ctx.invoke_count;
180	    ctx.invoke_count += 1;
181	
182	    let invoke_dir = ctx.burv_root.join(format!("invoke-{:05}", invoke_num));
183	    let burv_output = invoke_dir.join("output");
184	    let burv_temp = invoke_dir.join("temp");
185	
186	    std::fs::create_dir_all(&burv_output)
187	        .map_err(|e| format!("rbtdri: failed to create BURV output dir: {}", e))?;
188	    std::fs::create_dir_all(&burv_temp)
189	        .map_err(|e| format!("rbtdri: failed to create BURV temp dir: {}", e))?;
190	
191	    let mut cmd = Command::new(tabtarget);
192	    cmd.args(args)
193	        .current_dir(&ctx.project_root)
194	        .env("BURV_OUTPUT_ROOT_DIR", &burv_output)
195	        .env("BURV_TEMP_ROOT_DIR", &burv_temp);
196	
197	    for (key, value) in extra_env {
198	        cmd.env(key, value);
199	    }
200	
201	    let output = cmd
202	        .output()
203	        .map_err(|e| format!("rbtdri: failed to execute '{}': {}", tabtarget.display(), e))?;
204	
205	    Ok(rbtdri_InvokeResult {
206	        stdout: String::from_utf8_lossy(&output.stdout).into_owned(),
207	        stderr: String::from_utf8_lossy(&output.stderr).into_owned(),
208	        exit_code: output.status.code().unwrap_or(-1),
209	        burv_output,
210	    })
211	}
212	
213	/// Invoke a nameplate-scoped tabtarget (colophon + ctx.nameplate).
214	pub fn rbtdri_invoke(
215	    ctx: &mut rbtdri_Context,
216	    colophon: &str,
217	    args: &[&str],
218	) -> Result<rbtdri_InvokeResult, String> {
219	    let tabtarget = rbtdri_find_tabtarget(&ctx.project_root, colophon, &ctx.nameplate)?;
220	    rbtdri_invoke_impl(ctx, &tabtarget, args, &[])
221	}
222	
223	/// Invoke a global tabtarget (no imprint) with optional extra environment variables.
224	pub fn rbtdri_invoke_global(
225	    ctx: &mut rbtdri_Context,
226	    colophon: &str,
227	    args: &[&str],
228	    extra_env: &[(&str, &str)],
229	) -> Result<rbtdri_InvokeResult, String> {
230	    let tabtarget = rbtdri_find_tabtarget_global(&ctx.project_root, colophon)?;
231	    rbtdri_invoke_impl(ctx, &tabtarget, args, extra_env)
232	}
233	
234	/// Invoke a tabtarget with an explicit imprint (overrides ctx.nameplate for discovery).
235	pub fn rbtdri_invoke_imprint(
236	    ctx: &mut rbtdri_Context,
237	    colophon: &str,
238	    imprint: &str,
239	    args: &[&str],
240	) -> Result<rbtdri_InvokeResult, String> {
241	    let tabtarget = rbtdri_find_tabtarget(&ctx.project_root, colophon, imprint)?;
242	    rbtdri_invoke_impl(ctx, &tabtarget, args, &[])
243	}
244	
245	// ── BURV fact file reading ───────────────────────────────────
246	
247	/// Read a fact file from a tabtarget's BURV output directory.
248	/// Fact files are single-line values written by tabtargets to BURD_OUTPUT_DIR,
249	/// which is BURV_OUTPUT_ROOT_DIR/current per BUK dispatch convention.
250	pub fn rbtdri_read_burv_fact(
251	    result: &rbtdri_InvokeResult,
252	    fact_name: &str,
253	) -> Result<String, String> {
254	    let path = result.burv_output.join(RBTDRI_BURV_OUTPUT_SUBDIR).join(fact_name);
255	    let content = std::fs::read_to_string(&path)
256	        .map_err(|e| format!("rbtdri: cannot read fact '{}' from {}: {}", fact_name, path.display(), e))?;
257	    let trimmed = content.trim().to_string();
258	    if trimmed.is_empty() {
259	        return Err(format!("rbtdri: fact '{}' is empty in {}", fact_name, path.display()));
260	    }
261	    Ok(trimmed)
262	}
263	
264	// ── Ifrit verdict parsing ────────────────────────────────────
265	
266	/// Ifrit verdict wire protocol: ifrit prints exactly one line matching
267	/// `IFRIT_VERDICT: PASS` or `IFRIT_VERDICT: FAIL <detail>` to stdout.
268	/// Missing verdict line is always a failure — no silent pass-through.
269	pub fn rbtdri_parse_ifrit_verdict(stdout: &str, exit_code: i32) -> rbtdre_Verdict {
270	    for line in stdout.lines() {
271	        let trimmed = line.trim();
272	        if let Some(rest) = trimmed.strip_prefix("IFRIT_VERDICT:") {
273	            let rest = rest.trim();
274	            if rest.starts_with("PASS") {
275	                return rbtdre_Verdict::Pass;
276	            }
277	            if let Some(detail) = rest.strip_prefix("FAIL") {
278	                let detail = detail.trim();
279	                if detail.is_empty() {
280	                    return rbtdre_Verdict::Fail("ifrit reported failure".to_string());
281	                }
282	                return rbtdre_Verdict::Fail(detail.to_string());
283	            }
284	        }
285	    }
286	
287	    if exit_code == 0 {
288	        rbtdre_Verdict::Fail("ifrit exited 0 but no verdict line found".to_string())
289	    } else {
290	        rbtdre_Verdict::Fail(format!("ifrit exited {} with no verdict line", exit_code))
291	    }
292	}
293	
294	/// Invoke the ifrit binary inside a charged bottle via the bark tabtarget.
295	/// The attack selector argument tells ifrit which attack module to run.
296	/// Returns a test verdict based on ifrit's stdout verdict line and exit code.
297	pub fn rbtdri_invoke_ifrit(
298	    ctx: &mut rbtdri_Context,
299	    attack_selector: &str,
300	) -> Result<rbtdre_Verdict, String> {
301	    let result = rbtdri_invoke(ctx, RBTDRM_COLOPHON_BARK, &[RBTDRI_IFRIT_BINARY, attack_selector])?;
302	    Ok(rbtdri_parse_ifrit_verdict(&result.stdout, result.exit_code))
303	}
