36	/// RBRR field names referenced by the pristine-lifecycle fixture. Field
37	/// identifiers extracted as consts so the blank-field array and the
38	/// throwaway-prefix install helper share a single definition site.
39	const RBTDRP_FIELD_RBRR_CLOUD_PREFIX: &str = "RBRR_CLOUD_PREFIX";
40	const RBTDRP_FIELD_RBRR_RUNTIME_PREFIX: &str = "RBRR_RUNTIME_PREFIX";
41	const RBTDRP_FIELD_RBRR_DEPOT_MONIKER: &str = "RBRR_DEPOT_MONIKER";
42	
43	/// Site-specific RBRR fields that rblm_zero blanks. These three fields define
44	/// the depot-bound site identity (project ID, GAR repo, pool stem, and bucket
45	/// derive from CLOUD_PREFIX + DEPOT_MONIKER at kindle); an empty value is the
46	/// post-marshal-zero invariant.
47	const RBTDRP_RBRR_BLANK_FIELDS: &[&str] = &[
48	    RBTDRP_FIELD_RBRR_CLOUD_PREFIX,
49	    RBTDRP_FIELD_RBRR_RUNTIME_PREFIX,
50	    RBTDRP_FIELD_RBRR_DEPOT_MONIKER,
51	];
52	
53	/// Throwaway RBRR prefix values stamped into rbrr.env by
54	/// `rbtdrp_install_throwaway_prefixes`. Pristine-lifecycle cases that need
55	/// non-blank prefixes (depot/governor/retriever/director lifecycle) call the
56	/// helper to install these values; the marker shape distinguishes throwaway
57	/// from operator-chosen canonical values.
58	pub(crate) const RBTDRP_THROWAWAY_CLOUD_PREFIX: &str = "prlc-";
59	pub(crate) const RBTDRP_THROWAWAY_RUNTIME_PREFIX: &str = "prlr-";
60	
61	/// Family-stem prefixes for autodetected per-case monikers. Cases pick a
62	/// numeric six-digit suffix at runtime by walking emitted depot fact files
63	/// and incrementing past the highest existing suffix per family. Distinct
64	/// stems keep the two cases' depots separable when both run in the same
65	/// fixture pass.
66	const RBTDRP_FAMILY_STEM_LIFECYCLE: &str = "pristq";
67	const RBTDRP_FAMILY_STEM_GOVERNOR: &str = "pristg";
68	
69	/// Lowest valid numeric suffix for autodetected monikers. Six-digit width
70	/// keeps composed project_id length predictable: cloud_prefix(<=11) +
71	/// "d-"(2) + family(6) + suffix(6) = <=25, well under the 30-char GCP limit.
72	const RBTDRP_FAMILY_NUMERIC_FLOOR: u32 = 100000;
73	
74	/// Six-digit numeric suffix width — enforced when parsing existing fact-file
75	/// names so e.g. "pristq01" (legacy two-digit) is ignored rather than parsed
76	/// as 1 and shadowing real entries.
77	const RBTDRP_FAMILY_NUMERIC_WIDTH: usize = 6;
78	
79	/// Fact-file extension mirror of RBCC_fact_ext_depot in rbcc_Constants.sh.
80	/// rbgp_depot_list emits `<moniker>.depot` files with state content.
81	const RBTDRP_FACT_EXT_DEPOT: &str = "depot";
82	
83	/// Fact-file name for the governor SA email (mirror of
84	/// RBGP_FACT_GOVERNOR_SA_EMAIL from rbgc_Constants.sh). Read from the mantle
85	/// invocation's BURV output.
86	const RBTDRP_FACT_GOVERNOR_SA_EMAIL: &str = "rbgp_fact_governor_sa_email";
87	
88	/// BURE confirmation override (mirrors buc_command.sh): when set to "skip",
89	/// `buc_require` accepts the operation without interactive prompt.
90	const RBTDRP_BURE_CONFIRM_KEY: &str = "BURE_CONFIRM";
91	const RBTDRP_BURE_CONFIRM_SKIP: &str = "skip";
92	
93	/// `DELETE_REQUESTED` lifecycle state — appears in `rbgp_depot_list` output
94	/// after a soft-delete, used by case 2 to relax the post-unmake assertion.
95	const RBTDRP_DELETE_REQUESTED: &str = "DELETE_REQUESTED";
96	
97	/// Roles whose RBRA credential files rblm_zero deletes.
98	const RBTDRP_RBRA_ROLES: &[&str] = &["governor", "director", "retriever", "assay"];
99	
100	/// Nameplate hallmark fields rblm_zero blanks.
101	const RBTDRP_RBRN_BLANK_FIELDS: &[&str] = &["RBRN_SENTRY_HALLMARK", "RBRN_BOTTLE_HALLMARK"];
102	
103	/// File-relative constants matching rbbc_constants.sh / rbcc_Constants.sh.
104	const RBTDRP_DOT_DIR: &str = ".rbk";
105	const RBTDRP_RBRR_FILE: &str = ".rbk/rbrr.env";
106	const RBTDRP_RBRA_FILE: &str = "rbra.env";
107	const RBTDRP_RBRN_FILE: &str = "rbrn.env";
108	const RBTDRP_RBRV_FILE: &str = "rbrv.env";
109	
110	// ── Helpers ──────────────────────────────────────────────────
111	
112	/// Read an env file and return the value for `key`, or None if the key is
113	/// absent. The bash regime files use `KEY=value` lines (unquoted); comment
114	/// and blank lines are skipped. The trailing newline is stripped from value.
115	fn rbtdrp_read_env_value(path: &Path, key: &str) -> Option<String> {
116	    let content = std::fs::read_to_string(path).ok()?;
117	    let prefix = format!("{}=", key);
118	    for line in content.lines() {
119	        let trimmed = line.trim_start();
120	        if trimmed.starts_with('#') {
121	            continue;
122	        }
123	        if let Some(rest) = trimmed.strip_prefix(&prefix) {
124	            return Some(rest.to_string());
125	        }
126	    }
127	    None
128	}
129	
130	/// Resolve a path that may be absolute or relative-to-project-root.
131	fn rbtdrp_resolve(root: &Path, raw: &str) -> PathBuf {
132	    if Path::new(raw).is_absolute() {
133	        PathBuf::from(raw)
134	    } else {
135	        root.join(raw)
136	    }
137	}
138	
139	/// Class A — working tree clean (`git status --porcelain` empty).
140	fn rbtdrp_check_tree_clean(root: &Path, violations: &mut Vec<String>) {
141	    match Command::new("git")
142	        .args(["status", "--porcelain"])
143	        .current_dir(root)
144	        .output()
145	    {
146	        Ok(out) if out.status.success() => {
147	            let stdout = String::from_utf8_lossy(&out.stdout);
148	            let trimmed = stdout.trim();
149	            if !trimmed.is_empty() {
150	                violations.push(format!(
151	                    "working tree not clean — uncommitted changes:\n{}",
152	                    trimmed
153	                ));
154	            }
155	        }
156	        Ok(out) => violations.push(format!(
157	            "git status --porcelain failed (exit {}): {}",
158	            out.status.code().unwrap_or(-1),
159	            String::from_utf8_lossy(&out.stderr).trim()
160	        )),
161	        Err(e) => violations.push(format!("git status invocation failed: {}", e)),
162	    }
163	}
164	
165	/// Class B — five site-specific RBRR fields are blank.
166	fn rbtdrp_check_rbrr_fields(rbrr: &Path, violations: &mut Vec<String>) {
167	    for field in RBTDRP_RBRR_BLANK_FIELDS {
168	        if let Some(value) = rbtdrp_read_env_value(rbrr, field) {
169	            if !value.is_empty() {
170	                violations.push(format!(
171	                    "RBRR field non-blank: {}={} (in {})",
172	                    field,
173	                    value,
174	                    rbrr.display()
175	                ));
176	            }
177	        }
178	    }
179	}
180	
181	/// Class C — no RBRA credential files at the four role paths.
182	fn rbtdrp_check_rbra_files(root: &Path, secrets_dir: &str, violations: &mut Vec<String>) {
183	    if secrets_dir.is_empty() {
184	        violations.push(
185	            "RBRR_SECRETS_DIR is blank — cannot resolve credential paths".to_string(),
186	        );
187	        return;
188	    }
189	    let secrets = rbtdrp_resolve(root, secrets_dir);
190	    for role in RBTDRP_RBRA_ROLES {
191	        let path = secrets.join(role).join(RBTDRP_RBRA_FILE);
192	        if path.exists() {
193	            violations.push(format!("RBRA credential present: {}", path.display()));
194	        }
195	    }
196	}
197	
198	/// Class D — every nameplate's RBRN_SENTRY_HALLMARK and RBRN_BOTTLE_HALLMARK
199	/// is blank.
200	fn rbtdrp_check_nameplate_hallmarks(root: &Path, violations: &mut Vec<String>) {
201	    let dot_dir = root.join(RBTDRP_DOT_DIR);
202	    let entries = match std::fs::read_dir(&dot_dir) {
203	        Ok(e) => e,
204	        Err(e) => {
205	            violations.push(format!("cannot read {}: {}", dot_dir.display(), e));
206	            return;
207	        }
208	    };
209	    for entry in entries.flatten() {
210	        let np_dir = entry.path();
211	        if !np_dir.is_dir() {
212	            continue;
213	        }
214	        let rbrn = np_dir.join(RBTDRP_RBRN_FILE);
215	        if !rbrn.exists() {
216	            continue;
217	        }
218	        for field in RBTDRP_RBRN_BLANK_FIELDS {
219	            if let Some(value) = rbtdrp_read_env_value(&rbrn, field) {
220	                if !value.is_empty() {
221	                    violations.push(format!(
222	                        "nameplate hallmark non-blank: {}={} (in {})",
223	                        field,
224	                        value,
225	                        rbrn.display()
226	                    ));
227	                }
228	            }
229	        }
230	    }
231	}
