233	/// Class E — every vessel rbrv.env has RBRV_RELIQUARY blank and every
234	/// RBRV_IMAGE_*_ANCHOR field blank.
235	fn rbtdrp_check_vessel_depot_fields(
236	    root: &Path,
237	    vessel_dir: &str,
238	    violations: &mut Vec<String>,
239	) {
240	    if vessel_dir.is_empty() {
241	        violations.push("RBRR_VESSEL_DIR is blank — cannot scan vessels".to_string());
242	        return;
243	    }
244	    let vroot = rbtdrp_resolve(root, vessel_dir);
245	    let entries = match std::fs::read_dir(&vroot) {
246	        Ok(e) => e,
247	        Err(e) => {
248	            violations.push(format!("cannot read {}: {}", vroot.display(), e));
249	            return;
250	        }
251	    };
252	    for entry in entries.flatten() {
253	        let v_dir = entry.path();
254	        if !v_dir.is_dir() {
255	            continue;
256	        }
257	        let rbrv = v_dir.join(RBTDRP_RBRV_FILE);
258	        if !rbrv.exists() {
259	            continue;
260	        }
261	        rbtdrp_scan_rbrv_file(&rbrv, violations);
262	    }
263	}
