265	/// Scan a single rbrv.env for non-blank RBRV_RELIQUARY and RBRV_IMAGE_*_ANCHOR
266	/// fields.
267	fn rbtdrp_scan_rbrv_file(rbrv: &Path, violations: &mut Vec<String>) {
268	    let content = match std::fs::read_to_string(rbrv) {
269	        Ok(c) => c,
270	        Err(e) => {
271	            violations.push(format!("cannot read {}: {}", rbrv.display(), e));
272	            return;
273	        }
274	    };
275	    for line in content.lines() {
276	        let trimmed = line.trim_start();
277	        if trimmed.starts_with('#') {
278	            continue;
279	        }
280	        let (key, value) = match trimmed.split_once('=') {
281	            Some(kv) => kv,
282	            None => continue,
283	        };
284	        let is_reliquary = key == "RBRV_RELIQUARY";
285	        let is_anchor = key.starts_with("RBRV_IMAGE_") && key.ends_with("_ANCHOR");
286	        if (is_reliquary || is_anchor) && !value.is_empty() {
287	            violations.push(format!(
288	                "vessel depot-scoped field non-blank: {}={} (in {})",
289	                key,
290	                value,
291	                rbrv.display()
292	            ));
293	        }
294	    }
295	}
