297	// ── Env-file rewrite + git commit helpers ────────────────────
298	
299	/// Rewrite each line in `content` whose key matches an entry in `pairs`
300	/// (matched as `KEY=`) to `KEY=value`. Lines whose keys are not in `pairs`
301	/// pass through unchanged. The trailing-newline shape is preserved.
302	fn rbtdrp_replace_env_fields(content: &str, pairs: &[(&str, &str)]) -> String {
303	    let mut result: String = content
304	        .lines()
305	        .map(|line| {
306	            for (key, value) in pairs {
307	                let assign = format!("{}=", key);
308	                if line.starts_with(&assign) {
309	                    return format!("{}{}", assign, value);
310	                }
311	            }
312	            line.to_string()
313	        })
314	        .collect::<Vec<_>>()
315	        .join("\n");
316	    if content.ends_with('\n') {
317	        result.push('\n');
318	    }
319	    result
320	}
