322	/// `git add <file> && git commit -m <message>` from `root`. Bubbles the
323	/// underlying stderr on either step's failure.
324	fn rbtdrp_git_add_and_commit(root: &Path, file: &str, message: &str) -> Result<(), String> {
325	    let add = Command::new("git")
326	        .args(["add", file])
327	        .current_dir(root)
328	        .output()
329	        .map_err(|e| format!("rbtdrp: git add invocation failed: {}", e))?;
330	    if !add.status.success() {
331	        return Err(format!(
332	            "rbtdrp: git add failed (exit {}): {}",
333	            add.status.code().unwrap_or(-1),
334	            String::from_utf8_lossy(&add.stderr).trim()
335	        ));
336	    }
337	
338	    let commit = Command::new("git")
339	        .args(["commit", "-m", message])
340	        .current_dir(root)
341	        .output()
342	        .map_err(|e| format!("rbtdrp: git commit invocation failed: {}", e))?;
343	    if !commit.status.success() {
344	        return Err(format!(
345	            "rbtdrp: git commit failed (exit {}): {}",
346	            commit.status.code().unwrap_or(-1),
347	            String::from_utf8_lossy(&commit.stderr).trim()
348	        ));
349	    }
350	
351	    Ok(())
352	}
