354	// ── Throwaway-prefix install ─────────────────────────────────
355	
356	/// Idempotently install throwaway RBRR prefixes into `.rbk/rbrr.env`.
357	///
358	/// Pristine-lifecycle cases that need non-blank prefixes (depot/governor/
359	/// retriever/director lifecycle) call this as their first step. The helper
360	/// reads current values; if `RBRR_CLOUD_PREFIX` and `RBRR_RUNTIME_PREFIX`
361	/// already match the throwaway markers, returns `Ok(())` with no side
362	/// effect. Otherwise rewrites both lines in place, then `git add` +
363	/// `git commit` the change. One commit per fixture run regardless of which
364	/// case is the first to call it.
365	///
366	/// HEAD walks off marshal-zero after the commit; recovery is `rbw-MZ`,
367	/// matching the pristine fixture's start-over-from-zero failure mode.
368	pub(crate) fn rbtdrp_install_throwaway_prefixes(root: &Path) -> Result<(), String> {
369	    let rbrr = root.join(RBTDRP_RBRR_FILE);
370	    let cloud = rbtdrp_read_env_value(&rbrr, RBTDRP_FIELD_RBRR_CLOUD_PREFIX).unwrap_or_default();
371	    let runtime =
372	        rbtdrp_read_env_value(&rbrr, RBTDRP_FIELD_RBRR_RUNTIME_PREFIX).unwrap_or_default();
373	
374	    if cloud == RBTDRP_THROWAWAY_CLOUD_PREFIX && runtime == RBTDRP_THROWAWAY_RUNTIME_PREFIX {
375	        return Ok(());
376	    }
377	
378	    let content = std::fs::read_to_string(&rbrr)
379	        .map_err(|e| format!("rbtdrp: read {}: {}", rbrr.display(), e))?;
380	    let new_content = rbtdrp_replace_env_fields(
381	        &content,
382	        &[
383	            (RBTDRP_FIELD_RBRR_CLOUD_PREFIX, RBTDRP_THROWAWAY_CLOUD_PREFIX),
384	            (
385	                RBTDRP_FIELD_RBRR_RUNTIME_PREFIX,
386	                RBTDRP_THROWAWAY_RUNTIME_PREFIX,
387	            ),
388	        ],
389	    );
390	    std::fs::write(&rbrr, &new_content)
391	        .map_err(|e| format!("rbtdrp: write {}: {}", rbrr.display(), e))?;
392	
393	    let commit_msg = format!(
394	        "pristine-lifecycle fixture: install throwaway RBRR prefixes ({}/{})",
395	        RBTDRP_THROWAWAY_CLOUD_PREFIX, RBTDRP_THROWAWAY_RUNTIME_PREFIX
396	    );
397	    rbtdrp_git_add_and_commit(root, RBTDRP_RBRR_FILE, &commit_msg)
398	}
