487	/// Case 1 — marshal-zero attestation. Aggregates all five violation classes
488	/// into a single diagnostic. A passing run is the proof that `rbw-MZ` was
489	/// just executed and committed.
490	fn rbtdrp_marshal_zero_attestation(_dir: &Path) -> rbtdre_Verdict {
491	    let root = match std::env::current_dir() {
492	        Ok(r) => r,
493	        Err(e) => return rbtdre_Verdict::Fail(format!("cannot resolve project root: {}", e)),
494	    };
495	
496	    let rbrr = root.join(RBTDRP_RBRR_FILE);
497	    if !rbrr.exists() {
498	        return rbtdre_Verdict::Fail(format!("RBRR file not found: {}", rbrr.display()));
499	    }
500	
501	    let secrets_dir = rbtdrp_read_env_value(&rbrr, "RBRR_SECRETS_DIR").unwrap_or_default();
502	    let vessel_dir = rbtdrp_read_env_value(&rbrr, "RBRR_VESSEL_DIR").unwrap_or_default();
503	
504	    let mut violations: Vec<String> = Vec::new();
505	
506	    rbtdrp_check_tree_clean(&root, &mut violations);
507	    rbtdrp_check_rbrr_fields(&rbrr, &mut violations);
508	    rbtdrp_check_rbra_files(&root, &secrets_dir, &mut violations);
509	    rbtdrp_check_nameplate_hallmarks(&root, &mut violations);
510	    rbtdrp_check_vessel_depot_fields(&root, &vessel_dir, &mut violations);
511	
512	    if violations.is_empty() {
513	        return rbtdre_Verdict::Pass;
514	    }
515	
516	    let body = violations
517	        .iter()
518	        .map(|v| format!("  - {}", v))
519	        .collect::<Vec<_>>()
520	        .join("\n");
521	    rbtdre_Verdict::Fail(format!(
522	        "marshal-zero attestation failed — {} violation(s):\n{}\n\n\
523	         remedy: tt/rbw-MZ.MarshalZeroes.sh, then commit and rerun.",
524	        violations.len(),
525	        body
526	    ))
527	}
