549	/// Case 2 — depot-lifecycle. Probes existing depots via `rbgp_depot_list`,
550	/// picks the next free six-digit moniker in the `pristq` family, levies the
551	/// depot, asserts it appears in a follow-up `rbgp_depot_list`, soft-deletes
552	/// it via `rbgp_depot_unmake`, then asserts it is absent or in
553	/// `DELETE_REQUESTED` state.
554	///
555	/// Levy and unmake are zero-arg post-collapse — the moniker is set in
556	/// rbrr.env via `rbtdrp_install_depot_moniker` before levy invocation, and
557	/// the project_id is composed from regime values via `rbtdrp_compose_project_id`.
558	fn rbtdrp_depot_lifecycle(dir: &Path) -> rbtdre_Verdict {
559	    rbtdrc_with_ctx(|ctx| rbtdrp_depot_lifecycle_impl(ctx, dir))
560	}
561	
562	fn rbtdrp_depot_lifecycle_impl(ctx: &mut rbtdri_Context, dir: &Path) -> rbtdre_Verdict {
563	    let root = ctx.project_root().to_path_buf();
564	
565	    if let Err(e) = rbtdrp_install_throwaway_prefixes(&root) {
566	        return rbtdre_Verdict::Fail(format!("install throwaway prefixes: {}", e));
567	    }
568	
569	    let list_pre = match rbtdrp_invoke_logged(
570	        ctx,
571	        RBTDRM_COLOPHON_DEPOT_LIST,
572	        &[],
573	        &[],
574	        dir,
575	        "list-pre",
576	    ) {
577	        Ok(r) => r,
578	        Err(e) => return rbtdre_Verdict::Fail(format!("depot list (pre-levy probe): {}", e)),
579	    };
580	    if list_pre.exit_code != 0 {
581	        return rbtdre_Verdict::Fail(format!(
582	            "depot list (pre-levy probe) exit {}\n{}",
583	            list_pre.exit_code, list_pre.stderr
584	        ));
585	    }
586	
587	    let moniker = match rbtdrp_pick_next_moniker(&list_pre, RBTDRP_FAMILY_STEM_LIFECYCLE) {
588	        Ok(m) => m,
589	        Err(e) => return rbtdre_Verdict::Fail(format!("pick next moniker: {}", e)),
590	    };
591	    if let Err(e) = rbtdrp_install_depot_moniker(&root, &moniker) {
592	        return rbtdre_Verdict::Fail(format!("install depot moniker: {}", e));
593	    }
594	
595	    let levy = match rbtdrp_invoke_logged(
596	        ctx,
597	        RBTDRM_COLOPHON_DEPOT_LEVY,
598	        &[],
599	        &[],
600	        dir,
601	        "levy",
602	    ) {
603	        Ok(r) => r,
604	        Err(e) => return rbtdre_Verdict::Fail(format!("depot levy: {}", e)),
605	    };
606	    if levy.exit_code != 0 {
607	        return rbtdre_Verdict::Fail(format!(
608	            "depot levy exit {}\n{}",
609	            levy.exit_code, levy.stderr
610	        ));
611	    }
612	
613	    let project_id = match rbtdrp_compose_project_id(&root, &moniker) {
614	        Ok(p) => p,
615	        Err(e) => return rbtdre_Verdict::Fail(format!("compose project_id: {}", e)),
616	    };
617	    let _ = std::fs::write(dir.join("project-id.txt"), &project_id);
618	
619	    let list_present = match rbtdrp_invoke_logged(
620	        ctx,
621	        RBTDRM_COLOPHON_DEPOT_LIST,
622	        &[],
623	        &[],
624	        dir,
625	        "list-present",
626	    ) {
627	        Ok(r) => r,
628	        Err(e) => return rbtdre_Verdict::Fail(format!("depot list (after levy): {}", e)),
629	    };
630	    if list_present.exit_code != 0 {
631	        return rbtdre_Verdict::Fail(format!(
632	            "depot list (after levy) exit {}\n{}",
633	            list_present.exit_code, list_present.stderr
634	        ));
635	    }
636	    if !list_present.stdout.contains(&project_id) {
637	        return rbtdre_Verdict::Fail(format!(
638	            "project_id '{}' missing from depot list after levy:\n{}",
639	            project_id, list_present.stdout
640	        ));
641	    }
642	
643	    let unmake = match rbtdrp_invoke_logged(
644	        ctx,
645	        RBTDRM_COLOPHON_DEPOT_UNMAKE,
646	        &[],
647	        &[(RBTDRP_BURE_CONFIRM_KEY, RBTDRP_BURE_CONFIRM_SKIP)],
648	        dir,
649	        "unmake",
650	    ) {
651	        Ok(r) => r,
652	        Err(e) => return rbtdre_Verdict::Fail(format!("depot unmake: {}", e)),
653	    };
654	    if unmake.exit_code != 0 {
655	        return rbtdre_Verdict::Fail(format!(
656	            "depot unmake exit {}\n{}",
657	            unmake.exit_code, unmake.stderr
658	        ));
659	    }
660	
661	    let list_after = match rbtdrp_invoke_logged(
662	        ctx,
663	        RBTDRM_COLOPHON_DEPOT_LIST,
664	        &[],
665	        &[],
666	        dir,
667	        "list-after",
668	    ) {
669	        Ok(r) => r,
670	        Err(e) => return rbtdre_Verdict::Fail(format!("depot list (after unmake): {}", e)),
671	    };
672	    if list_after.exit_code != 0 {
673	        return rbtdre_Verdict::Fail(format!(
674	            "depot list (after unmake) exit {}\n{}",
675	            list_after.exit_code, list_after.stderr
676	        ));
677	    }
678	    for line in list_after.stdout.lines() {
679	        if line.contains(&project_id) && !line.contains(RBTDRP_DELETE_REQUESTED) {
680	            return rbtdre_Verdict::Fail(format!(
681	                "project_id '{}' still present without {} after unmake:\n{}",
682	                project_id, RBTDRP_DELETE_REQUESTED, line
683	            ));
684	        }
685	    }
686	
687	    rbtdre_Verdict::Pass
688	}
