690	/// Case 3 — governor-lifecycle. Probes existing depots, picks the next free
691	/// moniker in the `pristg` family, levies its own throwaway depot (so
692	/// `RBDC_DEPOT_PROJECT_ID` is set via kindle derivation, satisfying the
693	/// precondition for `rbgp_governor_mantle`), mantles a governor, asserts it
694	/// appears in `rbgg_list_service_accounts`, forfeits it, asserts absent,
695	/// then unmakes the depot to clean up.
696	///
697	/// `pristg` family stem keeps governor monikers separable from `pristq`
698	/// (case 2) when the full fixture runs.
699	fn rbtdrp_governor_lifecycle(dir: &Path) -> rbtdre_Verdict {
700	    rbtdrc_with_ctx(|ctx| rbtdrp_governor_lifecycle_impl(ctx, dir))
701	}
