703	fn rbtdrp_governor_lifecycle_impl(ctx: &mut rbtdri_Context, dir: &Path) -> rbtdre_Verdict {
704	    let root = ctx.project_root().to_path_buf();
705	
706	    if let Err(e) = rbtdrp_install_throwaway_prefixes(&root) {
707	        return rbtdre_Verdict::Fail(format!("install throwaway prefixes: {}", e));
708	    }
709	
710	    let list_pre = match rbtdrp_invoke_logged(
711	        ctx,
712	        RBTDRM_COLOPHON_DEPOT_LIST,
713	        &[],
714	        &[],
715	        dir,
716	        "list-pre",
717	    ) {
718	        Ok(r) => r,
719	        Err(e) => return rbtdre_Verdict::Fail(format!("depot list (pre-levy probe): {}", e)),
720	    };
721	    if list_pre.exit_code != 0 {
722	        return rbtdre_Verdict::Fail(format!(
723	            "depot list (pre-levy probe) exit {}\n{}",
724	            list_pre.exit_code, list_pre.stderr
725	        ));
726	    }
727	
728	    let moniker = match rbtdrp_pick_next_moniker(&list_pre, RBTDRP_FAMILY_STEM_GOVERNOR) {
729	        Ok(m) => m,
730	        Err(e) => return rbtdre_Verdict::Fail(format!("pick next moniker: {}", e)),
731	    };
732	    if let Err(e) = rbtdrp_install_depot_moniker(&root, &moniker) {
733	        return rbtdre_Verdict::Fail(format!("install depot moniker: {}", e));
734	    }
735	
736	    let levy = match rbtdrp_invoke_logged(
